import React, { useState, useEffect } from 'react';
import { EDUCATION_ITEMS, ENTERTAINMENT_ITEMS, UTILITIES_ITEMS } from './constants';
import { AppItem } from './types';
import AppCard from './components/AppCard';
import Modal from './components/Modal';
import Earth3D from './components/Earth3D';
import FoodChainApp from './components/FoodChainApp';
import CharacterApp from './components/CharacterApp';
import ClockApp from './components/ClockApp';
import WaveApp from './components/WaveApp';
import MathSprintApp from './components/MathSprintApp';
import HistorySortingApp from './components/HistorySortingApp';
import BrainTeaseApp from './components/BrainTeaseApp';
import GobangApp from './components/GobangApp';
import ChineseChessApp from './components/ChineseChessApp';
import ChessApp from './components/ChessApp';
import ProArtApp from './components/ProArtApp';
import VocabularyApp from './components/VocabularyApp';
import IdiomApp from './components/IdiomApp';
import PoetryApp from './components/PoetryApp';
import ThreeCharacterApp from './components/ThreeCharacterApp';
import ThousandCharacterApp from './components/ThousandCharacterApp';
import HeroSpotlight from './components/HeroSpotlight';
import LibraryView from './components/LibraryView';
import SettingsView from './components/SettingsView';
import ExploreView from './components/ExploreView';
import { Search, Grid2X2, Compass, Heart, Settings, Plus, BookOpen, Loader2, Sparkles, Moon, Sun } from 'lucide-react';
import { AnimatePresence } from 'framer-motion';

type Tab = 'HOME' | 'EXPLORE' | 'LIBRARY' | 'PROFILE';
type Theme = 'light' | 'dark';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('HOME');
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  const [savedIds, setSavedIds] = useState<string[]>([]);
  const [historyIds, setHistoryIds] = useState<string[]>([]);
  const [user, setUser] = useState<{ email: string } | null>(null);
  const [theme, setTheme] = useState<Theme>(() => (localStorage.getItem('zst_theme') as Theme) || 'light');

  const allModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const savedIden = localStorage.getItem('zst_identity');
    if (savedIden) setUser(JSON.parse(savedIden));
    const storedSaved = localStorage.getItem('zst_saved_v2');
    if (storedSaved) setSavedIds(JSON.parse(storedSaved));
    const storedHistory = localStorage.getItem('zst_history_v2');
    if (storedHistory) setHistoryIds(JSON.parse(storedHistory));
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('zst_theme', theme);
  }, [theme]);

  const handleToggleSave = (id: string) => {
    const newSaved = savedIds.includes(id) ? savedIds.filter(i => i !== id) : [...savedIds, id];
    setSavedIds(newSaved);
    localStorage.setItem('zst_saved_v2', JSON.stringify(newSaved));
  };

  const addToHistory = (id: string) => {
    const filtered = historyIds.filter(i => i !== id);
    const newHistory = [id, ...filtered].slice(0, 15);
    setHistoryIds(newHistory);
    localStorage.setItem('zst_history_v2', JSON.stringify(newHistory));
  };

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);
    addToHistory(item.id);
    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 800);
  };

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e21': return <ThousandCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return null;
    }
  };

  if (runningAppId) return renderApp();

  const renderContent = () => {
    switch (activeTab) {
      case 'EXPLORE': return <ExploreView />;
      case 'LIBRARY': return <LibraryView allModules={allModules} savedIds={savedIds} historyIds={historyIds} onOpenItem={setSelectedItem} />;
      case 'PROFILE': return <SettingsView theme={theme} onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')} />;
      default:
        return (
          <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
            <main className="max-w-4xl mx-auto px-6 pt-4">
              {!searchQuery && activeCategory === 'ALL' && (
                <HeroSpotlight item={allModules[0]} onRun={handleRunApp} />
              )}
              <section className="mb-6">
                <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
                  {['ALL', 'EDUCATION', 'ENTERTAINMENT', 'UTILITIES'].map((cat) => (
                    <button
                      key={cat}
                      onClick={() => setActiveCategory(cat)}
                      className={`px-6 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${activeCategory === cat ? 'bg-morandi-charcoal text-white dark:bg-slate-200 dark:text-dark-bg border-morandi-charcoal dark:border-slate-200 shadow-sm' : 'bg-white text-slate-400 border-slate-200 dark:bg-dark-card dark:text-slate-500 dark:border-white/5'}`}
                    >
                      {cat === 'ALL' ? '全部' : cat === 'EDUCATION' ? '自然科学' : cat === 'ENTERTAINMENT' ? '逻辑数学' : '通用工具'}
                    </button>
                  ))}
                </div>
              </section>
              <div className="grid grid-cols-1 gap-1">
                {filteredModules.map((item) => (
                  <AppCard key={item.id} item={item} onClick={setSelectedItem} />
                ))}
              </div>
            </main>
          </div>
        );
    }
  };

  return (
    <div className="h-screen bg-morandi-oatmeal dark:bg-dark-bg text-morandi-charcoal dark:text-slate-300 flex flex-col overflow-hidden transition-colors duration-300">
      {/* 极简顶部栏 */}
      <header className="shrink-0 px-6 pt-12 pb-6 flex items-center justify-between bg-morandi-oatmeal/80 dark:bg-dark-bg/80 backdrop-blur-md sticky top-0 z-50 transition-colors">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 flex items-center justify-center bg-white dark:bg-dark-card rounded-xl shadow-sm border border-slate-100 dark:border-white/5">
            <span className="material-icons-outlined text-morandi-charcoal dark:text-slate-300 text-2xl">auto_awesome_motion</span>
          </div>
          <div>
            <h1 className="text-2xl font-bold tracking-tight text-morandi-charcoal dark:text-slate-100">
              {activeTab === 'HOME' ? '发现' : activeTab === 'EXPLORE' ? '探索' : activeTab === 'LIBRARY' ? '收藏' : '设置'}
            </h1>
            <p className="text-[10px] text-slate-400 dark:text-slate-500 font-bold uppercase tracking-wider">
              {activeTab === 'HOME' ? 'Icon Library' : 'Navigation'}
            </p>
          </div>
        </div>
        <button className="w-10 h-10 flex items-center justify-center bg-white dark:bg-dark-card rounded-full shadow-sm border border-slate-50 dark:border-white/5">
          <span className="material-icons-outlined text-slate-400 dark:text-slate-500 text-xl">search</span>
        </button>
      </header>

      <AnimatePresence mode="wait">
        <div className="flex-1 overflow-hidden flex flex-col">
          {renderContent()}
        </div>
      </AnimatePresence>

      {/* iOS 风格底部导航 */}
      <footer className="shrink-0 bg-white/95 dark:bg-dark-card/95 backdrop-blur-xl border-t border-slate-100 dark:border-white/5 pb-8 pt-3 px-6 safe-bottom z-50 transition-colors">
        <div className="flex justify-between items-center max-w-lg mx-auto relative">
          <NavButton icon="grid_view" label="首页" active={activeTab === 'HOME'} onClick={() => setActiveTab('HOME')} />
          <NavButton icon="explore" label="探索" active={activeTab === 'EXPLORE'} onClick={() => setActiveTab('EXPLORE')} />

          <div className="absolute left-1/2 -translate-x-1/2 -top-10">
            <button className="w-14 h-14 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl shadow-xl flex items-center justify-center transform active:scale-90 transition-all">
              <span className="material-icons-outlined text-3xl">add</span>
            </button>
          </div>

          <NavButton icon="favorite_border" label="收藏" active={activeTab === 'LIBRARY'} onClick={() => setActiveTab('LIBRARY')} className="ml-12" />
          <NavButton icon="settings" label="设置" active={activeTab === 'PROFILE'} onClick={() => setActiveTab('PROFILE')} />
        </div>
      </footer>

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          isSaved={savedIds.includes(selectedItem.id)}
          onToggleSave={handleToggleSave}
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

const NavButton = ({ icon, label, active, onClick, className = "" }: { icon: string, label: string, active?: boolean, onClick: () => void, className?: string }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1 w-16 transition-all ${className} ${active ? 'text-morandi-charcoal dark:text-slate-100' : 'text-slate-300 dark:text-slate-600'}`}>
    <span className="material-icons-outlined text-2xl">{icon}</span>
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

import React from 'react';
import { AppItem } from '../types';
import { MoreHorizontal } from 'lucide-react';
import { motion } from 'framer-motion';

interface AppCardProps {
  item: AppItem;
  onClick: (item: AppItem) => void;
}

const AppCard: React.FC<AppCardProps> = ({ item, onClick }) => {
  // 核心视觉映射：根据图标功能匹配参考图中的配色方案
  const getTheme = () => {
    const icon = item.icon || 'auto_awesome_motion';

    // 蓝色系 (地理、天文、语言、波) -> 匹配 3D地球
    if (['public', 'language', 'waves', 'translate', 'explore', 'map'].includes(icon)) {
      return { bg: 'bg-[#B0BEC5] dark:bg-[#546E7A]', iconColor: 'text-white/80' };
    }
    // 黄色系 (逻辑、数学、创意) -> 匹配 逻辑思维
    if (['lightbulb', 'calculate', 'functions', 'psychology', 'brain', 'schedule'].includes(icon)) {
      return { bg: 'bg-[#FFE082] dark:bg-[#D4AF37]/40', iconColor: 'text-yellow-700/60 dark:text-yellow-200/60' };
    }
    // 绿色系 (科学、生物、国学、艺术) -> 匹配 微观世界/三字经
    if (['science', 'pest_control', 'eco', 'menu_book', 'auto_stories', 'import_contacts', 'history_edu', 'palette', 'spellcheck'].includes(icon)) {
      return { bg: 'bg-[#A5D6A7] dark:bg-[#2E7D32]/40', iconColor: 'text-green-700/60 dark:text-green-200/60' };
    }

    // 默认莫兰迪蓝灰色
    return { bg: 'bg-[#9EB3C2] dark:bg-[#455A64]', iconColor: 'text-white/80' };
  };

  const theme = getTheme();

  return (
    <motion.div 
      initial={{ opacity: 0, y: 10 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      whileTap={{ scale: 0.98 }}
      className="group relative bg-white dark:bg-dark-card rounded-ios overflow-hidden border border-morandi-border dark:border-white/5 soft-shadow transition-all hover:bg-white dark:hover:bg-[#252529] cursor-pointer mb-4"
      onClick={() => onClick(item)}
    >
      <div className="flex p-5 gap-6 items-center">
        {/* iOS 风格图标容器 */}
        <div className={`w-20 h-20 md:w-24 md:h-24 flex-shrink-0 rounded-[1.8rem] flex items-center justify-center shadow-sm relative overflow-hidden ${theme.bg}`}>
          {/* 背景装饰 */}
          <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent opacity-50"></div>

          <span className={`material-icons-outlined text-4xl md:text-5xl relative z-10 ${theme.iconColor}`}>
            {item.icon || 'auto_awesome_motion'}
          </span>

          {/* 装饰圆圈 */}
          <div className="absolute w-12 h-12 border border-white/10 rounded-full -top-2 -right-2"></div>
          <div className="absolute w-20 h-[1px] bg-white/10 top-1/2 left-2 rotate-45"></div>
        </div>

        {/* 右侧信息 */}
        <div className="flex-1 min-w-0">
          <div className="flex justify-between items-start mb-1">
            <h4 className="text-lg font-bold text-morandi-charcoal dark:text-slate-100 truncate tracking-tight serif-font">
              {item.title}
            </h4>
            <button className="text-slate-200 dark:text-slate-700 hover:text-morandi-taupe transition-colors">
              <MoreHorizontal size={20} />
            </button>
          </div>
          <p className="text-slate-400 dark:text-slate-500 text-xs leading-relaxed mb-3 font-medium line-clamp-2 italic">
            {item.description}
          </p>
          <div className="flex gap-2">
            <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600 border border-slate-100 dark:border-white/5`}>
              {item.category.toUpperCase()}
            </span>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default AppCard;

import React from 'react';
import { User, Bell, Palette, Info, ExternalLink, LogOut, ChevronRight, Sparkles, Moon, Sun } from 'lucide-react';
import { motion } from 'framer-motion';

interface SettingsViewProps {
  theme: 'light' | 'dark';
  onToggleTheme: () => void;
}

const SettingsView: React.FC<SettingsViewProps> = ({ theme, onToggleTheme }) => {
  return (
    <motion.div 
      initial={{ opacity: 0, y: 10 }} 
      animate={{ opacity: 1, y: 0 }}
      className="flex-1 flex flex-col px-6 pt-10 overflow-y-auto no-scrollbar pb-24"
    >
      {/* 个人资料卡片 */}
      <div className="flex flex-col items-center mb-12">
        <div className="relative mb-4">
          <div className="w-28 h-28 rounded-full border-2 border-morandi-taupe/30 dark:border-slate-800 p-1.5 overflow-hidden">
            <div className="w-full h-full rounded-full bg-morandi-blue/20 dark:bg-slate-800/50 flex items-center justify-center relative transition-colors">
               <div className="absolute inset-0 watercolor-fill opacity-30 dark:opacity-10 bg-morandi-blue dark:bg-slate-200"></div>
               <User size={48} className="text-morandi-blue dark:text-slate-400" />
            </div>
          </div>
          <div className="absolute -bottom-1 -right-1 w-8 h-8 bg-white dark:bg-dark-card border border-morandi-border dark:border-white/5 rounded-full flex items-center justify-center text-amber-500 shadow-sm transition-colors">
            <Sparkles size={16} />
          </div>
        </div>
        <h2 className="text-xl font-bold text-morandi-charcoal dark:text-slate-100 serif-font">Julian Vance</h2>
        <p className="text-xs text-morandi-taupe dark:text-slate-500 font-medium mt-1">国际象棋 & 地球探索者</p>
      </div>

      {/* 设置组 */}
      <div className="space-y-4">
        <div className="bg-white/60 dark:bg-dark-card/60 border border-morandi-border dark:border-white/5 rounded-[2.5rem] overflow-hidden soft-shadow px-2 transition-colors">
          <SettingItem icon={<User size={18} />} label="账号管理" />
          <Divider />
          <SettingItem icon={<Bell size={18} />} label="推送通知" />
          <Divider />
          <SettingItem 
            icon={theme === 'light' ? <Sun size={18} /> : <Moon size={18} />} 
            label="视觉主题" 
            value={theme === 'light' ? '莫兰迪燕麦' : '黑曜石深邃'} 
            onClick={onToggleTheme}
          />
          <Divider />
          <SettingItem icon={<Info size={18} />} label="关于我们" />
        </div>

        <div className="bg-white/60 dark:bg-dark-card/60 border border-morandi-border dark:border-white/5 rounded-[2.5rem] p-2 soft-shadow transition-colors">
          <SettingItem icon={<ExternalLink size={18} />} label="支持中心" />
        </div>

        <div className="flex flex-col items-center pt-8">
          <button className="text-morandi-rose dark:text-rose-400 font-bold text-sm flex items-center gap-2 hover:opacity-70 transition-opacity">
            <LogOut size={16} />
            <span>退出当前节点</span>
          </button>
          <p className="text-[9px] text-morandi-border dark:text-slate-800 font-black uppercase tracking-[0.3em] mt-6">Version 2.5.0 — Dark Mode Ready</p>
        </div>
      </div>
    </motion.div>
  );
};

const SettingItem = ({ icon, label, value, onClick }: { icon: React.ReactNode, label: string, value?: string, onClick?: () => void }) => (
  <button onClick={onClick} className="w-full px-6 py-4 flex items-center justify-between hover:bg-white dark:hover:bg-white/5 transition-colors group">
    <div className="flex items-center gap-4">
      <div className="text-morandi-taupe dark:text-slate-500 group-hover:text-morandi-charcoal dark:group-hover:text-slate-200 transition-colors">{icon}</div>
      <span className="text-sm font-bold text-morandi-charcoal dark:text-slate-200">{label}</span>
    </div>
    <div className="flex items-center gap-2">
      {value && <span className="text-xs text-morandi-taupe dark:text-slate-500 font-medium">{value}</span>}
      <ChevronRight size={16} className="text-morandi-border dark:text-slate-800" />
    </div>
  </button>
);

const Divider = () => <div className="h-px bg-morandi-border/30 dark:bg-white/5 mx-6" />;

export default SettingsView;

import React, { useEffect, useState } from 'react';
import { X, Heart, Share2, Info, PlayCircle, CheckCircle2 } from 'lucide-react';
import { AppItem } from '../types';
import { motion, AnimatePresence } from 'framer-motion';

interface ModalProps {
  item: AppItem;
  isSaved: boolean;
  onToggleSave: (id: string) => void;
  onClose: () => void;
  onRun: (item: AppItem) => void;
  user: { email: string } | null;
}

const Modal: React.FC<ModalProps> = ({ item, isSaved, onToggleSave, onClose, onRun, user }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [copyFeedback, setCopyFeedback] = useState(false);

  useEffect(() => {
    setIsVisible(true);
    document.body.style.overflow = 'hidden';
    return () => {
      document.body.style.overflow = 'auto';
    };
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  return (
    <div className={`fixed inset-0 z-50 flex items-end md:items-center justify-center transition-all duration-300 ${isVisible ? 'bg-morandi-charcoal/20 dark:bg-black/60 backdrop-blur-md' : 'bg-transparent pointer-events-none'}`} onClick={handleClose}>
      <div 
        className={`relative w-full md:max-w-2xl h-[85dvh] md:h-auto bg-morandi-oatmeal dark:bg-dark-bg shadow-2xl rounded-t-[3rem] md:rounded-[3rem] overflow-hidden transform transition-all duration-300 border border-morandi-border dark:border-white/5 ${isVisible ? 'translate-y-0 opacity-100' : 'translate-y-full opacity-0'}`}
        onClick={(e) => e.stopPropagation()}
      >
        <div className="absolute top-4 right-4 z-10">
          <button onClick={handleClose} className="p-2 bg-white/80 dark:bg-dark-card/80 hover:bg-white dark:hover:bg-dark-card rounded-full transition-colors border border-morandi-border dark:border-white/5 text-morandi-taupe">
            <X size={20} />
          </button>
        </div>

        <div className="h-48 md:h-64 overflow-hidden relative">
          <img src={item.imageUrl} className="w-full h-full object-cover" alt={item.title} />
          <div className="absolute inset-0 bg-gradient-to-t from-morandi-oatmeal dark:from-dark-bg via-transparent to-transparent"></div>
          <div className="absolute bottom-6 left-8">
            <h2 className="text-3xl md:text-5xl font-bold text-morandi-charcoal dark:text-white serif-font">{item.title}</h2>
          </div>
        </div>

        <div className="p-8 md:p-12 space-y-8 overflow-y-auto max-h-[calc(85dvh-16rem)] no-scrollbar transition-colors">
          <section>
            <div className="flex items-center gap-2 mb-4 text-morandi-taupe dark:text-slate-500">
              <Info size={16} />
              <h3 className="text-[10px] font-bold uppercase tracking-widest">模块简介</h3>
            </div>
            <p className="text-lg text-morandi-charcoal dark:text-slate-300 leading-relaxed font-light italic">
              {item.description}
            </p>
          </section>

          <div className="flex flex-wrap gap-2">
            {item.tags.map(tag => (
              <span key={tag} className="px-4 py-1.5 bg-white dark:bg-dark-card border border-morandi-border dark:border-white/5 text-morandi-taupe dark:text-slate-500 text-[10px] font-bold rounded-xl">
                #{tag}
              </span>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-4 pt-4 pb-8">
            <button 
              onClick={() => onRun(item)}
              className="flex-1 py-4 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl font-bold flex items-center justify-center gap-3 shadow-lg active:scale-95 transition-all hover:bg-black dark:hover:bg-white"
            >
              <PlayCircle size={24} />
              <span>启动程序</span>
            </button>
            <div className="flex gap-4">
              <motion.button 
                whileTap={{ scale: 1.2 }}
                onClick={() => onToggleSave(item.id)}
                className={`w-14 h-14 border rounded-2xl flex items-center justify-center transition-all shadow-sm ${isSaved ? 'bg-morandi-rose border-morandi-rose text-white' : 'bg-white dark:bg-dark-card border-morandi-border dark:border-white/5 text-morandi-rose hover:bg-morandi-rose/5'}`}
              >
                <Heart size={20} fill={isSaved ? "currentColor" : "none"} />
              </motion.button>
