/**
 * 五子棋 AI 引擎 PRO - 优化版
 * 极大极小值算法 (Minimax) + Alpha-Beta 剪枝 + 动态启发式评估
 */

export type Player = 1 | 2; // 1: 黑子(玩家), 2: 白子(AI)
export type Board = (Player | 0)[][];

const BOARD_SIZE = 15;

// 增强版评分表
const SCORE = {
  FIVE: 10000000,
  LIVE_FOUR: 1000000,
  SLEEP_FOUR: 100000,
  LIVE_THREE: 100000,
  SLEEP_THREE: 10000,
  LIVE_TWO: 10000,
  SLEEP_TWO: 1000,
  ANY_ONE: 100
};

export function evaluateBoard(board: Board, player: Player): number {
  let totalScore = 0;
  for (let r = 0; r < BOARD_SIZE; r++) {
    for (let c = 0; c < BOARD_SIZE; c++) {
      const cell = board[r][c];
      if (cell !== 0) {
        const score = getPosScore(board, r, c, cell);
        totalScore += cell === player ? score : -score;
      }
    }
  }
  return totalScore;
}

function getPosScore(board: Board, r: number, c: number, p: Player): number {
  let score = 0;
  const directions = [[0, 1], [1, 0], [1, 1], [1, -1]];

  for (const [dr, dc] of directions) {
    let count = 1;
    let block = 0;

    let currR = r + dr, currC = c + dc;
    while (currR >= 0 && currR < BOARD_SIZE && currC >= 0 && currC < BOARD_SIZE && board[currR][currC] === p) {
      count++; currR += dr; currC += dc;
    }
    if (!(currR >= 0 && currR < BOARD_SIZE && currC >= 0 && currC < BOARD_SIZE && board[currR][currC] === 0)) block++;

    currR = r - dr; currC = c - dc;
    while (currR >= 0 && currR < BOARD_SIZE && currC >= 0 && currC < BOARD_SIZE && board[currR][currC] === p) {
      count++; currR -= dr; currC -= dc;
    }
    if (!(currR >= 0 && currR < BOARD_SIZE && currC >= 0 && currC < BOARD_SIZE && board[currR][currC] === 0)) block++;

    if (count >= 5) score += SCORE.FIVE;
    else if (count === 4) score += block === 0 ? SCORE.LIVE_FOUR : (block === 1 ? SCORE.SLEEP_FOUR : 0);
    else if (count === 3) score += block === 0 ? SCORE.LIVE_THREE : (block === 1 ? SCORE.SLEEP_THREE : 0);
    else if (count === 2) score += block === 0 ? SCORE.LIVE_TWO : (block === 1 ? SCORE.SLEEP_TWO : 0);
  }
  return score;
}

export function checkWin(board: Board, r: number, c: number): boolean {
  const p = board[r][c];
  if (p === 0) return false;
  const directions = [[0, 1], [1, 0], [1, 1], [1, -1]];
  for (const [dr, dc] of directions) {
    let count = 1;
    let nr = r + dr, nc = c + dc;
    while (nr >= 0 && nr < BOARD_SIZE && nc >= 0 && nc < BOARD_SIZE && board[nr][nc] === p) {
      count++; nr += dr; nc += dc;
    }
    nr = r - dr; nc = c - dc;
    while (nr >= 0 && nr < BOARD_SIZE && nc >= 0 && nc < BOARD_SIZE && board[nr][nc] === p) {
      count++; nr -= dr; nc -= dc;
    }
    if (count >= 5) return true;
  }
  return false;
}

export function getBestMove(board: Board, depth: number = 2): [number, number] {
  let bestVal = -Infinity;
  let bestMove: [number, number] = [-1, -1];

  const candidates: [number, number, number][] = [];
  for (let r = 0; r < BOARD_SIZE; r++) {
    for (let c = 0; c < BOARD_SIZE; c++) {
      if (board[r][c] === 0 && hasNeighbor(board, r, c)) {
        const priority = getPosScore(board, r, c, 2) * 1.1 + getPosScore(board, r, c, 1);
        candidates.push([r, c, priority]);
      }
    }
  }

  candidates.sort((a, b) => b[2] - a[2]);
  if (candidates.length === 0) return [7, 7];

  for (const [r, c] of candidates.slice(0, 15)) {
    board[r][c] = 2;
    const val = minimax(board, depth - 1, false, -Infinity, Infinity);
    board[r][c] = 0;
    if (val > bestVal) {
      bestVal = val;
      bestMove = [r, c];
    }
  }
  return bestMove;
}

function hasNeighbor(board: Board, r: number, c: number): boolean {
  for (let dr = -1; dr <= 1; dr++) {
    for (let dc = -1; dc <= 1; dc++) {
      if (dr === 0 && dc === 0) continue;
      const nr = r + dr, nc = c + dc;
      if (nr >= 0 && nr < BOARD_SIZE && nc >= 0 && nc < BOARD_SIZE && board[nr][nc] !== 0) return true;
    }
  }
  return false;
}

function minimax(board: Board, depth: number, isMaximizing: boolean, alpha: number, beta: number): number {
  if (depth === 0) return evaluateBoard(board, 2);

  const candidates: [number, number][] = [];
  for (let r = 0; r < BOARD_SIZE; r++) {
    for (let c = 0; c < BOARD_SIZE; c++) {
      if (board[r][c] === 0 && hasNeighbor(board, r, c)) candidates.push([r, c]);
    }
  }

  if (isMaximizing) {
    let maxEval = -Infinity;
    for (const [r, c] of candidates) {
      board[r][c] = 2;
      const ev = minimax(board, depth - 1, false, alpha, beta);
      board[r][c] = 0;
      maxEval = Math.max(maxEval, ev);
      alpha = Math.max(alpha, ev);
      if (beta <= alpha) break;
    }
    return maxEval;
  } else {
    let minEval = Infinity;
    for (const [r, c] of candidates) {
      board[r][c] = 1;
      const ev = minimax(board, depth - 1, true, alpha, beta);
      board[r][c] = 0;
      minEval = Math.min(minEval, ev);
      beta = Math.min(beta, ev);
      if (beta <= alpha) break;
    }
    return minEval;
  }
}

export function getScoreMap(board: Board, player: Player): number[][] {
  const scoreMap = Array(BOARD_SIZE).fill(0).map(() => Array(BOARD_SIZE).fill(0));
  for (let r = 0; r < BOARD_SIZE; r++) {
    for (let c = 0; c < BOARD_SIZE; c++) {
      if (board[r][c] === 0) {
        scoreMap[r][c] = getPosScore(board, r, c, player);
      }
    }
  }
  return scoreMap;
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
// Added ChevronRight to the lucide-react imports
import { X, RotateCcw, Undo2, BrainCircuit, Trophy, Settings2, Play, ChevronLeft, ChevronRight, Lightbulb, Timer, Footprints, ShieldCheck } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Player, Board, checkWin, getBestMove, getScoreMap } from '../lib/gobangAI';

const BOARD_SIZE = 15;

type GameState = 'SELECTION' | 'PLAYING' | 'SETTLEMENT';
type Difficulty = 'EASY' | 'MEDIUM' | 'HARD';

const GobangApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [gameState, setGameState] = useState<GameState>('SELECTION');
  const [difficulty, setDifficulty] = useState<Difficulty>('MEDIUM');
  const [board, setBoard] = useState<Board>(Array(15).fill(null).map(() => Array(15).fill(0)));
  const [currentPlayer, setCurrentPlayer] = useState<Player>(1); 
  const [winner, setWinner] = useState<Player | 'Draw' | null>(null);
  const [history, setHistory] = useState<Board[]>([]);
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [lastMove, setLastMove] = useState<[number, number] | null>(null);
  const [hint, setHint] = useState<[number, number] | null>(null);

  // 计时状态
  const [timers, setTimers] = useState({ p1: 300, p2: 300 });
  const timerRef = useRef<any>(null);

  // 初始化游戏
  const startNewGame = (diff: Difficulty) => {
    setDifficulty(diff);
    setBoard(Array(15).fill(null).map(() => Array(15).fill(0)));
    setHistory([]);
    setCurrentPlayer(1);
    setWinner(null);
    setLastMove(null);
    setHint(null);
    setTimers({ p1: 300, p2: 300 });
    setGameState('PLAYING');
  };

  // 计时逻辑
  useEffect(() => {
    if (gameState === 'PLAYING' && !winner) {
      timerRef.current = setInterval(() => {
        setTimers(prev => {
          if (currentPlayer === 1) return { ...prev, p1: Math.max(0, prev.p1 - 1) };
          return { ...prev, p2: Math.max(0, prev.p2 - 1) };
        });
      }, 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [gameState, currentPlayer, winner]);

  const handlePlaceStone = (r: number, c: number) => {
    if (winner || board[r][c] !== 0 || isAiThinking) return;

    const newBoard = board.map(row => [...row]);
    newBoard[r][c] = currentPlayer;
    setHistory(prev => [...prev, board.map(row => [...row])]);
    setBoard(newBoard);
    setLastMove([r, c]);
    setHint(null);

    if (checkWin(newBoard, r, c)) {
      setWinner(currentPlayer);
      setGameState('SETTLEMENT');
      return;
    }

    const nextPlayer = (currentPlayer === 1 ? 2 : 1) as Player;
    setCurrentPlayer(nextPlayer);

    if (nextPlayer === 2) {
      setIsAiThinking(true);
      const depth = difficulty === 'EASY' ? 1 : difficulty === 'MEDIUM' ? 2 : 4;
      setTimeout(() => {
        const [aiR, aiC] = getBestMove(newBoard, depth);
        if (aiR !== -1) {
          const aiBoard = newBoard.map(row => [...row]);
          aiBoard[aiR][aiC] = 2;
          setBoard(aiBoard);
          setLastMove([aiR, aiC]);
          if (checkWin(aiBoard, aiR, aiC)) {
            setWinner(2);
            setGameState('SETTLEMENT');
          } else {
            setCurrentPlayer(1);
          }
        }
        setIsAiThinking(false);
      }, 600);
    }
  };

  const undoMove = () => {
    if (history.length < 2 || isAiThinking) return;
    const previousState = history[history.length - 2];
    setBoard(previousState);
    setHistory(prev => prev.slice(0, -2));
    setLastMove(null);
    setWinner(null);
  };

  const getHint = () => {
    if (isAiThinking || winner) return;
    const [hintR, hintC] = getBestMove(board, 2);
    setHint([hintR, hintC]);
    setTimeout(() => setHint(null), 3000);
  };

