);

const PlayerCard = ({ name, time, active, stone, round, status }: any) => (
  <div className={`flex-1 p-4 rounded-2xl backdrop-blur-md border-2 transition-all ${active ? `bg-white/80 dark:bg-black/40 border-primary shadow-xl scale-105` : `bg-white/40 dark:bg-black/10 border-transparent opacity-60`}`}>
    <div className="flex items-center gap-2 mb-2">
      <div className={`w-3 h-3 rounded-full ${stone === 'black' ? 'bg-black' : 'bg-white border border-slate-200'} shadow-sm`}></div>
      <span className={`text-[10px] font-black uppercase tracking-widest ${active ? 'text-primary' : 'text-slate-500'}`}>{name}</span>
