  const SelectionView = () => (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="w-full max-w-md flex flex-col gap-6 px-4">
      <div className="text-center mb-4">
        <h2 className="text-4xl font-extrabold text-slate-800 dark:text-white mb-2 serif-font italic">博弈禅</h2>
        <p className="text-slate-500 font-medium">请选择您的挑战难度</p>
      </div>
      <div className="space-y-4">
        <DifficultyCard title="入门级" desc="适合新手学习规则" icon="spa" color="emerald" onClick={() => startNewGame('EASY')} />
        <DifficultyCard title="进阶级" desc="挑战自我对弈策略" icon="grid_on" color="orange" onClick={() => startNewGame('MEDIUM')} />
        <DifficultyCard title="大师级" desc="顶尖算力对决" icon="military_tech" color="purple" onClick={() => startNewGame('HARD')} />
      </div>
    </motion.div>
  );

  const PlayingView = () => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-w-md flex flex-col items-center px-4">
      <div className="w-full flex justify-between gap-4 mb-6">
        <PlayerCard name="你" time={formatTime(timers.p1)} active={currentPlayer === 1} stone="black" round={history.length + 1} />
        <PlayerCard name="AI对手" time={formatTime(timers.p2)} active={currentPlayer === 2} stone="white" status={isAiThinking ? "思考中..." : "等待中..."} />
      </div>

      <div className="w-full aspect-square relative mb-8 group bg-[#e3d5c6] rounded-xl shadow-2xl p-4 sm:p-6 border-[8px] border-[#917b5e]">
         <div className="absolute inset-0 opacity-[0.15] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/wood-pattern-with-fine-lines.png')]"></div>
         <div className="absolute -left-6 top-6 bottom-6 flex flex-col justify-between text-[8px] font-bold text-slate-500 font-mono">
            {Array.from({length: 15}).map((_, i) => <span key={i}>{15-i}</span>)}
         </div>
         <div className="absolute -bottom-6 left-6 right-6 flex justify-between text-[8px] font-bold text-slate-500 font-mono">
            {Array.from({length: 15}).map((_, i) => <span key={i}>{String.fromCharCode(65+i)}</span>)}
         </div>
         <div className="w-full h-full relative grid grid-cols-15 grid-rows-15 border border-[#a69b91]/30">
            {board.map((row, r) => row.map((cell, c) => (
              <div key={`${r}-${c}`} onClick={() => handlePlaceStone(r, c)} className="relative w-full h-full flex items-center justify-center cursor-pointer group/cell">
                <div className="absolute w-px h-full bg-[#a69b91]/40 left-1/2"></div>
                <div className="absolute h-px w-full bg-[#a69b91]/40 top-1/2"></div>
                {cell === 0 && !winner && !isAiThinking && (
                  <div className={`w-3/4 h-3/4 rounded-full opacity-0 group-hover/cell:opacity-20 transition-opacity ${currentPlayer === 1 ? 'bg-black' : 'bg-white'}`}></div>
                )}
                {hint && hint[0] === r && hint[1] === c && (
                  <div className="absolute w-2 h-2 bg-emerald-50 rounded-full animate-ping z-20"></div>
                )}
                {cell !== 0 && (
                  <motion.div 
                    initial={{ scale: 0, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                    className={`w-[90%] h-[90%] rounded-full shadow-stone relative z-10 ${cell === 1 ? 'bg-stone-black shadow-stone-black-inner' : 'bg-stone-white shadow-stone-white-inner'} ${lastMove?.[0] === r && lastMove?.[1] === c ? 'ring-2 ring-primary ring-offset-2 ring-offset-[#e3d5c6]' : ''}`}
                  >
                     <div className="absolute top-1 left-2 w-1.5 h-1.5 bg-white/20 rounded-full blur-[1px]"></div>
                  </motion.div>
                )}
              </div>
            )))}
         </div>
      </div>

      <div className="w-full max-xs bg-white/80 dark:bg-black/30 backdrop-blur-md rounded-2xl p-2 shadow-xl flex items-center justify-between gap-2 border border-white/20">
         <ActionButton icon={<Undo2 size={18}/>} label="悔棋" onClick={undoMove} disabled={history.length === 0 || isAiThinking} />
         <div className="w-px h-8 bg-slate-200 dark:bg-slate-800"></div>
         <ActionButton icon={<Lightbulb size={18}/>} label="提示" onClick={getHint} color="primary" disabled={isAiThinking} />
         <div className="w-px h-8 bg-slate-200 dark:bg-slate-800"></div>
         <ActionButton icon={<RotateCcw size={18}/>} label="重置" onClick={() => setGameState('SELECTION')} danger />
      </div>
    </motion.div>
  );

  const SettlementView = () => (
    <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm">
      <div className="bg-white dark:bg-[#1E2322] w-full max-w-xs rounded-3xl overflow-hidden shadow-2xl">
        <div className="pt-8 px-6 pb-2 text-center flex flex-col items-center">
          <div className={`w-16 h-16 rounded-full flex items-center justify-center mb-4 ${winner === 1 ? 'bg-primary/10 text-primary' : 'bg-rose-100 text-rose-500'}`}>
            <Trophy size={32} />
          </div>
          <h2 className="text-2xl font-black text-slate-800 dark:text-white mb-1 serif-font">
            {winner === 1 ? '祝贺你，获胜！' : '很遗憾，失败了'}
          </h2>
          <p className="text-slate-500 text-sm">{winner === 1 ? '精彩的对弈，完美的胜利' : '总结经验，再接再厉'}</p>
        </div>
        <div className="px-6 py-4 flex gap-3">
           <StatBox icon={<Footprints size={14}/>} label="总步数" value={history.length + 1} />
           <StatBox icon={<Timer size={14}/>} label="用时" value={formatTime(winner === 1 ? 300 - timers.p1 : 300 - timers.p2)} />
        </div>
        <div className="px-6 pb-8 flex flex-col gap-3">
          <button onClick={() => startNewGame(difficulty)} className="w-full py-4 bg-primary text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-primary/20 active:scale-95 transition-all">
            <RotateCcw size={18} /> 再来一局
          </button>
          <button onClick={() => setGameState('SELECTION')} className="w-full py-4 bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-300 rounded-xl font-bold transition-all">
            返回选择
          </button>
        </div>
      </div>
    </motion.div>
  );

  return (
    <div className="fixed inset-0 z-[60] bg-background-light dark:bg-background-dark flex flex-col items-center overflow-hidden">
      <header className="w-full flex items-center justify-between px-6 pt-12 pb-4 z-10 shrink-0">
        <button onClick={onClose} className="p-2 hover:bg-black/5 dark:hover:bg-white/10 rounded-full transition-colors">
          <ChevronLeft size={24} />
        </button>
        <div className="flex flex-col items-center">
          <h1 className="text-xl font-black tracking-tight text-slate-800 dark:text-slate-100 serif-font italic">博弈禅 · 五子棋</h1>
          {gameState === 'PLAYING' && <span className="text-[9px] font-black uppercase bg-primary/10 text-primary px-3 py-0.5 rounded-full mt-1">难度: {difficulty === 'EASY' ? '入门' : difficulty === 'MEDIUM' ? '中等' : '大师'}</span>}
        </div>
        <button className="p-2 text-slate-300 dark:text-slate-600">
          <Settings2 size={20} />
        </button>
      </header>

      <main className="flex-1 w-full flex flex-col items-center justify-center p-6 pb-12 relative overflow-y-auto no-scrollbar">
         {gameState === 'SELECTION' && <SelectionView />}
         {gameState === 'PLAYING' && <PlayingView />}
         {gameState === 'SETTLEMENT' && <SettlementView />}
      </main>

      <style>{`
        .serif-font { font-family: 'Noto Serif SC', serif; }
        .shadow-stone { box-shadow: 1px 3px 4px rgba(0,0,0,0.3); }
        .bg-stone-black { background: radial-gradient(circle at 35% 35%, #555, #000); }
        .bg-stone-white { background: radial-gradient(circle at 35% 35%, #fff, #ddd); }
        .shadow-stone-black-inner { box-shadow: inset 2px 2px 6px rgba(255,255,255,0.1); }
        .shadow-stone-white-inner { box-shadow: inset -2px -2px 6px rgba(0,0,0,0.1); }
      `}</style>
    </div>
  );
};

