    <div className="text-[8px] font-bold text-slate-400 uppercase tracking-widest mt-1">{label}</div>
  </div>
);

export default GobangApp;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { X, RotateCcw, Undo2, Trophy, Settings2, ChevronLeft, ChevronRight, Lightbulb, Timer, Footprints } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Player, Board, checkWin, getBestMove } from '../lib/gobangAI';

const BOARD_SIZE = 15;

type GameState = 'SELECTION' | 'PLAYING' | 'SETTLEMENT';
type Difficulty = 'EASY' | 'MEDIUM' | 'HARD';

const GobangApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [gameState, setGameState] = useState<GameState>('SELECTION');
  const [difficulty, setDifficulty] = useState<Difficulty>('MEDIUM');
  const [board, setBoard] = useState<Board>(Array(15).fill(null).map(() => Array(15).fill(0)));
  const [currentPlayer, setCurrentPlayer] = useState<Player>(1); 
  const [winner, setWinner] = useState<Player | 'Draw' | null>(null);
  const [history, setHistory] = useState<Board[]>([]); 
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [lastMove, setLastMove] = useState<[number, number] | null>(null);
  const [hint, setHint] = useState<[number, number] | null>(null);

  const [timers, setTimers] = useState({ p1: 300, p2: 300 });
  const timerRef = useRef<any>(null);

  const startNewGame = (diff: Difficulty) => {
    setDifficulty(diff);
    setBoard(Array(15).fill(null).map(() => Array(15).fill(0)));
    setHistory([]);
    setCurrentPlayer(1);
    setWinner(null);
    setLastMove(null);
    setHint(null);
    setTimers({ p1: 300, p2: 300 });
    setGameState('PLAYING');
  };

  const triggerAiMove = useCallback((currentBoard: Board) => {
    setIsAiThinking(true);
    const depth = difficulty === 'EASY' ? 1 : difficulty === 'MEDIUM' ? 2 : 4;

    setTimeout(() => {
      const [aiR, aiC] = getBestMove(currentBoard, depth);
      if (aiR !== -1) {
        const aiBoard = currentBoard.map(row => [...row]);
        aiBoard[aiR][aiC] = 2;
        setBoard(aiBoard);
        setLastMove([aiR, aiC]);
        if (checkWin(aiBoard, aiR, aiC)) {
          setWinner(2);
          setTimeout(() => setGameState('SETTLEMENT'), 600);
        } else {
          setCurrentPlayer(1);
        }
      }
      setIsAiThinking(false);
    }, 600);
  }, [difficulty]);

  const handlePlaceStone = (r: number, c: number) => {
    if (winner || board[r][c] !== 0 || isAiThinking || currentPlayer !== 1) return;

    const boardBeforeMove = board.map(row => [...row]);
    const newBoard = board.map(row => [...row]);
    newBoard[r][c] = 1;

    setHistory(prev => [...prev, boardBeforeMove]);
    setBoard(newBoard);
    setLastMove([r, c]);
    setHint(null);

    if (checkWin(newBoard, r, c)) {
      setWinner(1);
      setTimeout(() => setGameState('SETTLEMENT'), 600);
      return;
    }

    setCurrentPlayer(2);
    triggerAiMove(newBoard);
  };

  const undoMove = () => {
    if (history.length === 0 || isAiThinking || winner) return;
    const lastHistory = [...history];
    const previousState = lastHistory.pop();
    if (previousState) {
      setBoard(previousState);
      setHistory(lastHistory);
      setLastMove(null);
      setWinner(null);
      setCurrentPlayer(1);
      setHint(null);
    }
  };

  useEffect(() => {
    if (gameState === 'PLAYING' && !winner) {
      timerRef.current = setInterval(() => {
        setTimers(prev => {
          if (currentPlayer === 1) return { ...prev, p1: Math.max(0, prev.p1 - 1) };
          return { ...prev, p2: Math.max(0, prev.p2 - 1) };
        });
      }, 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [gameState, currentPlayer, winner]);

  const getHint = () => {
    if (isAiThinking || winner || currentPlayer !== 1) return;
    const [hintR, hintC] = getBestMove(board, 2);
    setHint([hintR, hintC]);
    setTimeout(() => setHint(null), 3000);
  };

  const formatTime = (s: number) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  const SelectionView = () => (
    <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} className="w-full max-w-md flex flex-col gap-6 px-4">
      <div className="text-center mb-4">
        <h2 className="text-4xl font-extrabold text-slate-800 dark:text-white mb-2 serif-font italic">博弈禅</h2>
        <p className="text-slate-500 font-medium">请选择您的挑战难度</p>
      </div>
      <div className="space-y-4">
        <DifficultyCard title="入门级" desc="适合新手学习规则" icon="spa" color="emerald" onClick={() => startNewGame('EASY')} />
        <DifficultyCard title="进阶级" desc="挑战自我对弈策略" icon="grid_on" color="orange" onClick={() => startNewGame('MEDIUM')} />
        <DifficultyCard title="大师级" desc="顶尖算力对决" icon="military_tech" color="purple" onClick={() => startNewGame('HARD')} />
      </div>
    </motion.div>
  );

  const PlayingView = () => (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-w-md flex flex-col items-center px-4 flex-shrink-0">
      {/* 顶部选手卡片 */}
      <div className="w-full flex justify-between gap-4 mb-8 flex-shrink-0">
        <PlayerCard name="你" time={formatTime(timers.p1)} active={currentPlayer === 1} stone="black" round={history.length + 1} />
        <PlayerCard name="AI对手" time={formatTime(timers.p2)} active={currentPlayer === 2} stone="white" status={isAiThinking ? "思考中..." : "等待中..."} />
      </div>

      {/* 核心棋盘 */}
      <div className="w-full max-w-[min(100vw-3rem,400px)] aspect-square relative mb-12 group bg-[#e3d5c6] rounded-xl shadow-2xl p-4 sm:p-6 border-[8px] border-[#917b5e] flex-shrink-0">
         <div className="absolute inset-0 opacity-[0.15] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/wood-pattern-with-fine-lines.png')]"></div>

         {/* 坐标 A-O */}
         <div className="absolute -bottom-6 left-4 right-4 flex justify-between text-[8px] font-bold text-slate-400 font-mono">
            {Array.from({length: 15}).map((_, i) => <span key={i} className="w-[6.66%] text-center">{String.fromCharCode(65+i)}</span>)}
         </div>
         {/* 坐标 1-15 */}
         <div className="absolute -left-6 top-4 bottom-4 flex flex-col justify-between text-[8px] font-bold text-slate-400 font-mono">
            {Array.from({length: 15}).map((_, i) => <span key={i} className="h-[6.66%] flex items-center">{15-i}</span>)}
         </div>

         {/* 网格容器 - 关键修复：显式内联栅格 */}
         <div 
           className="w-full h-full relative grid border border-[#a69b91]/30"
           style={{ 
             gridTemplateColumns: 'repeat(15, 1fr)', 
             gridTemplateRows: 'repeat(15, 1fr)' 
           }}
         >
            {board.map((row, r) => row.map((cell, c) => (
              <div 
                key={`${r}-${c}`} 
                onClick={() => handlePlaceStone(r, c)} 
                className="relative w-full h-full flex items-center justify-center cursor-pointer group/cell"
              >
                {/* 绘制十字线 */}
                <div className="absolute w-px h-full bg-[#a69b91]/50 left-1/2 -translate-x-1/2"></div>
                <div className="absolute h-px w-full bg-[#a69b91]/50 top-1/2 -translate-y-1/2"></div>

                {/* 落子预览 */}
                {cell === 0 && !winner && !isAiThinking && (
                  <div className={`w-[80%] h-[80%] rounded-full opacity-0 group-hover/cell:opacity-20 transition-opacity z-10 ${currentPlayer === 1 ? 'bg-black' : 'bg-white'}`}></div>
                )}

                {/* AI提示点 */}
                {hint && hint[0] === r && hint[1] === c && (
                  <div className="absolute w-2 h-2 bg-emerald-500 rounded-full animate-ping z-20"></div>
                )}

                {/* 棋子渲染 */}
                {cell !== 0 && (
                  <motion.div 
                    initial={{ scale: 0, opacity: 0 }} 
                    animate={{ scale: 1, opacity: 1 }}
                    className={`
                      w-[90%] h-[90%] rounded-full shadow-stone relative z-20
                      ${cell === 1 ? 'bg-stone-black shadow-stone-black-inner' : 'bg-stone-white shadow-stone-white-inner'} 
                      ${lastMove?.[0] === r && lastMove?.[1] === c ? 'ring-2 ring-primary ring-offset-2 ring-offset-[#e3d5c6]' : ''}
                    `}
                  >
                     <div className="absolute top-1 left-2 w-1.5 h-1.5 bg-white/20 rounded-full blur-[1px]"></div>
                  </motion.div>
                )}
              </div>
            )))}
         </div>
      </div>

      {/* 控制栏 */}
      <div className="w-full max-w-xs bg-white dark:bg-dark-card rounded-[2rem] p-2 soft-shadow border border-morandi-border dark:border-white/5 flex items-center justify-between gap-2 flex-shrink-0">
         <ActionButton icon={<Undo2 size={20}/>} label="悔棋" onClick={undoMove} disabled={history.length === 0 || isAiThinking} />
         <div className="w-px h-10 bg-morandi-border dark:bg-white/5"></div>
         <ActionButton icon={<Lightbulb size={20}/>} label="提示" onClick={getHint} color="primary" disabled={isAiThinking || winner} />
         <div className="w-px h-10 bg-morandi-border dark:bg-white/5"></div>
         <ActionButton icon={<RotateCcw size={20}/>} label="重置" onClick={() => setGameState('SELECTION')} danger />
      </div>
    </motion.div>
  );

  const SettlementView = () => (
    <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm">
      <div className="bg-white dark:bg-dark-card w-full max-w-xs rounded-[3rem] overflow-hidden soft-shadow border border-morandi-border dark:border-white/5">
        <div className="pt-10 px-8 pb-4 text-center flex flex-col items-center">
          <div className={`w-20 h-20 rounded-full flex items-center justify-center mb-6 ${winner === 1 ? 'bg-emerald-50 text-emerald-500' : 'bg-rose-50 text-rose-500'}`}>
            <Trophy size={40} />
          </div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2 serif-font italic">
            {winner === 1 ? '祝贺你，获胜！' : '很遗憾，失败了'}
          </h2>
          <p className="text-slate-400 text-xs font-medium uppercase tracking-widest">{winner === 1 ? 'Master of Strategy' : 'Better Luck Next Time'}</p>
        </div>
        <div className="px-8 py-6 flex gap-4">
           <StatBox icon={<Footprints size={16}/>} label="总步数" value={history.length + 1} />
           <StatBox icon={<Timer size={16}/>} label="用时" value={formatTime(winner === 1 ? 300 - timers.p1 : 300 - timers.p2)} />
        </div>
        <div className="px-8 pb-10 flex flex-col gap-3">
          <button onClick={() => startNewGame(difficulty)} className="w-full py-4 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl font-bold flex items-center justify-center gap-3 shadow-lg active:scale-95 transition-all">
            <RotateCcw size={18} /> 再来一局
