      </div>

      {/* 棋盘主体容器 - 采用 padding-bottom 稳固高度 */}
      <div className="w-full max-w-[400px] mb-12 shrink-0">
        <div className="relative w-full bg-[#e3d5c6] rounded-xl shadow-2xl border-[8px] border-[#917b5e]" style={{ paddingBottom: '100%', height: 0 }}>
          <div className="absolute inset-0 p-4 sm:p-6 overflow-visible">
             <div className="absolute inset-0 opacity-[0.15] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/wood-pattern-with-fine-lines.png')]"></div>

             {/* 坐标 A-O */}
             <div className="absolute -bottom-8 left-4 right-4 flex justify-between text-[10px] font-bold text-slate-400 font-mono">
                {Array.from({length: 15}).map((_, i) => <span key={i} className="w-full text-center">{String.fromCharCode(65+i)}</span>)}
             </div>
             {/* 坐标 1-15 */}
             <div className="absolute -left-8 top-4 bottom-4 flex flex-col justify-between text-[10px] font-bold text-slate-400 font-mono">
                {Array.from({length: 15}).map((_, i) => <span key={i} className="h-full flex items-center">{15-i}</span>)}
             </div>

             {/* 棋盘格 - 使用绝对定位撑满父级容器 */}
             <div 
               className="absolute inset-4 sm:inset-6 grid border border-[#a69b91]/40"
               style={{ 
                 gridTemplateColumns: 'repeat(15, 1fr)', 
                 gridTemplateRows: 'repeat(15, 1fr)' 
               }}
             >
                {board.map((row, r) => row.map((cell, c) => (
                  <div 
                    key={`${r}-${c}`} 
                    onClick={() => handlePlaceStone(r, c)} 
                    className="relative w-full h-full flex items-center justify-center cursor-pointer group/cell"
                  >
                    {/* 十字准星线 */}
                    <div className="absolute w-[1px] h-full bg-[#a69b91]/60 left-1/2 -translate-x-1/2"></div>
                    <div className="absolute h-[1px] w-full bg-[#a69b91]/60 top-1/2 -translate-y-1/2"></div>

                    {/* 落子反馈层 */}
                    {cell === 0 && !winner && !isAiThinking && (
                      <div className={`w-[85%] h-[85%] rounded-full opacity-0 group-hover/cell:opacity-20 transition-opacity z-10 ${currentPlayer === 1 ? 'bg-black' : 'bg-white'}`}></div>
                    )}

                    {/* 提示动画点 */}
                    {hint && hint[0] === r && hint[1] === c && (
                      <div className="absolute w-2 h-2 bg-emerald-500 rounded-full animate-ping z-20"></div>
                    )}

                    {/* 棋子 */}
                    {cell !== 0 && (
                      <motion.div 
                        initial={{ scale: 0, opacity: 0 }} 
                        animate={{ scale: 1, opacity: 1 }}
                        className={`
                          w-[94%] h-[94%] rounded-full shadow-stone relative z-20
                          ${cell === 1 ? 'bg-stone-black shadow-stone-black-inner' : 'bg-stone-white shadow-stone-white-inner'} 
                          ${lastMove?.[0] === r && lastMove?.[1] === c ? 'ring-2 ring-primary ring-offset-2 ring-offset-[#e3d5c6]' : ''}
                        `}
                      >
                         <div className="absolute top-1 left-2 w-1.5 h-1.5 bg-white/20 rounded-full blur-[1px]"></div>
                      </motion.div>
                    )}
                  </div>
                )))}
             </div>
          </div>
        </div>
      </div>

      {/* 控制栏 */}
      <div className="w-full max-w-xs bg-white dark:bg-dark-card rounded-[2rem] p-2 soft-shadow border border-morandi-border dark:border-white/5 flex items-center justify-between gap-1 shrink-0">
         <ActionButton icon={<Undo2 size={20}/>} label="悔棋" onClick={undoMove} disabled={history.length === 0 || isAiThinking} />
         <div className="w-px h-10 bg-morandi-border dark:bg-white/5"></div>
         <ActionButton icon={<Lightbulb size={20}/>} label="提示" onClick={getHint} color="primary" disabled={isAiThinking || winner} />
         <div className="w-px h-10 bg-morandi-border dark:bg-white/5"></div>
         <ActionButton icon={<RotateCcw size={20}/>} label="重置" onClick={() => setGameState('SELECTION')} danger />
      </div>
    </motion.div>
  );

  const SettlementView = () => (
    <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm">
      <div className="bg-white dark:bg-dark-card w-full max-w-xs rounded-[3rem] overflow-hidden soft-shadow border border-morandi-border dark:border-white/5">
        <div className="pt-10 px-8 pb-4 text-center flex flex-col items-center">
          <div className={`w-20 h-20 rounded-full flex items-center justify-center mb-6 ${winner === 1 ? 'bg-emerald-50 text-emerald-500' : 'bg-rose-50 text-rose-500'}`}>
            <Trophy size={40} />
          </div>
          <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-2 serif-font italic">
            {winner === 1 ? '祝贺你，获胜！' : '很遗憾，失败了'}
          </h2>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">{winner === 1 ? 'Master of Strategy' : 'Try Again for Zen'}</p>
        </div>
        <div className="px-8 py-6 flex gap-4">
           <StatBox icon={<Footprints size={16}/>} label="总步数" value={history.length + 1} />
           <StatBox icon={<Timer size={16}/>} label="用时" value={formatTime(winner === 1 ? 300 - timers.p1 : 300 - timers.p2)} />
        </div>
        <div className="px-8 pb-10 flex flex-col gap-3">
          <button onClick={() => startNewGame(difficulty)} className="w-full py-4 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl font-bold flex items-center justify-center gap-3 shadow-lg active:scale-95 transition-all">
            <RotateCcw size={18} /> 再来一局
          </button>
          <button onClick={() => setGameState('SELECTION')} className="w-full py-4 bg-white dark:bg-slate-800 text-slate-400 dark:text-slate-300 rounded-2xl font-bold border border-morandi-border dark:border-white/5 transition-all">
            返回主页
          </button>
        </div>
      </div>
    </motion.div>
  );

  return (
    <div className="fixed inset-0 z-[60] bg-morandi-oatmeal dark:bg-dark-bg flex flex-col items-center overflow-hidden">
      <header className="w-full flex items-center justify-between px-6 pt-12 pb-6 z-10 shrink-0 bg-morandi-oatmeal/80 dark:bg-dark-bg/80 backdrop-blur-md">
        <button onClick={onClose} className="w-10 h-10 flex items-center justify-center bg-white dark:bg-dark-card rounded-full soft-shadow text-slate-400 transition-all hover:scale-105 active:scale-95">
          <ChevronLeft size={24} />
        </button>
        <div className="flex flex-col items-center">
          <h1 className="text-xl font-bold tracking-tight text-morandi-charcoal dark:text-slate-100 serif-font italic">博弈禅 · 五子棋</h1>
