import React, { useState, useEffect } from 'react';
import { Sparkles, RefreshCw, Zap, Globe, Book, Rocket, Cpu, Loader2 } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { AppItem } from '../types';

interface KnowledgeBannerProps {
  onRun: (id: string) => void;
}

const KnowledgeBanner: React.FC<KnowledgeBannerProps> = ({ onRun }) => {
  const [wisdom, setWisdom] = useState<string>('正在同步全息知识库...');
  const [isLoading, setIsLoading] = useState(false);

  const fetchWisdom = async () => {
    setIsLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: "请生成一条简短的、富有哲理的知识洞察，要求融合自然科学与人文精神，字数在30字以内。格式如：‘在量子力学的尺度下，万物皆有回响，诚如古人云...’",
      });
      setWisdom(response.text || '宇宙的尽头是数学，而数学的终点是诗意。');
    } catch (e) {
      setWisdom('思维火花暂歇，探索永不止步。');
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchWisdom();
  }, []);

  return (
    <section className="mt-1 mb-6 relative group">
      {/* 动态背景背景 */}
      <div className="absolute -inset-1 bg-gradient-to-r from-morandi-blue/20 via-morandi-rose/20 to-morandi-sage/20 rounded-[2rem] blur-xl opacity-50 group-hover:opacity-100 transition-opacity duration-700"></div>

      <div className="relative overflow-hidden rounded-[1.8rem] bg-white/70 dark:bg-dark-card/70 backdrop-blur-2xl border border-white dark:border-white/5 shadow-sm p-5 md:p-6 flex flex-col md:flex-row items-center gap-6">

        {/* 左侧：AI 灵感区 */}
        <div className="flex-1 min-w-0 w-full">
          <div className="flex items-center gap-2 mb-3">
            <div className="p-1.5 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-lg shadow-inner">
              <Sparkles size={14} className={isLoading ? 'animate-pulse' : ''} />
            </div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-morandi-taupe dark:text-slate-500 italic">Neural_Insight</span>
            {isLoading && <Loader2 size={10} className="animate-spin text-morandi-taupe" />}
          </div>

          <div className="min-h-[3rem] flex flex-col justify-center">
             <p className={`text-sm md:text-base font-bold text-morandi-charcoal dark:text-slate-200 serif-font italic leading-relaxed transition-all duration-500 ${isLoading ? 'opacity-30 blur-sm' : 'opacity-100 blur-0'}`}>
                “{wisdom}”
             </p>
          </div>

          <button 
            onClick={fetchWisdom}
            disabled={isLoading}
            className="mt-3 flex items-center gap-1.5 text-[9px] font-black text-morandi-taupe hover:text-morandi-charcoal dark:hover:text-slate-200 transition-colors uppercase tracking-widest disabled:opacity-50"
          >
            <RefreshCw size={10} className={isLoading ? 'animate-spin' : ''} />
            刷新灵感
          </button>
        </div>

        {/* 分隔线 (桌面端) */}
        <div className="hidden md:block w-px h-16 bg-morandi-border dark:bg-white/5"></div>

        {/* 右侧：快速导航矩阵 */}
        <div className="grid grid-cols-4 gap-3 md:gap-4 shrink-0">
          <QuickAction icon={<Globe size={18}/>} label="3D地球" onClick={() => onRun('e1')} />
          <QuickAction icon={<Book size={18}/>} label="诗词馆" onClick={() => onRun('e5')} />
          <QuickAction icon={<Zap size={18}/>} label="速算王" onClick={() => onRun('e18')} />
          <QuickAction icon={<Cpu size={18}/>} label="AI对弈" onClick={() => onRun('ent6')} />
        </div>
      </div>
    </section>
  );
};

