);

export default KnowledgeBanner;

import React, { useState, useEffect } from 'react';
import { EDUCATION_ITEMS, ENTERTAINMENT_ITEMS, UTILITIES_ITEMS } from './constants';
import { AppItem } from './types';
import AppCard from './components/AppCard';
import Modal from './components/Modal';
import KnowledgeBanner from './components/KnowledgeBanner';
import Earth3D from './components/Earth3D';
import FoodChainApp from './components/FoodChainApp';
import CharacterApp from './components/CharacterApp';
import ClockApp from './components/ClockApp';
import WaveApp from './components/WaveApp';
import MathSprintApp from './components/MathSprintApp';
import HistorySortingApp from './components/HistorySortingApp';
import BrainTeaseApp from './components/BrainTeaseApp';
import GobangApp from './components/GobangApp';
import ChineseChessApp from './components/ChineseChessApp';
import ChessApp from './components/ChessApp';
import ProArtApp from './components/ProArtApp';
import VocabularyApp from './components/VocabularyApp';
import IdiomApp from './components/IdiomApp';
import PoetryApp from './components/PoetryApp';
import ThreeCharacterApp from './components/ThreeCharacterApp';
import ThousandCharacterApp from './components/ThousandCharacterApp';
import LibraryView from './components/LibraryView';
import SettingsView from './components/SettingsView';
import ExploreView from './components/ExploreView';
import { AnimatePresence } from 'framer-motion';
import { Search } from 'lucide-react';

type Tab = 'HOME' | 'EXPLORE' | 'LIBRARY' | 'PROFILE';
type Theme = 'light' | 'dark';

export interface UserInfo {
  email: string;
  avatarUrl: string;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('HOME');
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  const [savedIds, setSavedIds] = useState<string[]>([]);
  const [historyIds, setHistoryIds] = useState<string[]>([]);
  const [user, setUser] = useState<UserInfo | null>(null);
  const [theme, setTheme] = useState<Theme>(() => (localStorage.getItem('zst_theme') as Theme) || 'light');

  const allModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const savedIden = localStorage.getItem('zst_identity_v3');
    if (savedIden) setUser(JSON.parse(savedIden));
    const storedSaved = localStorage.getItem('zst_saved_v2');
    if (storedSaved) setSavedIds(JSON.parse(storedSaved));
    const storedHistory = localStorage.getItem('zst_history_v2');
    if (storedHistory) setHistoryIds(JSON.parse(storedHistory));
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('zst_theme', theme);
  }, [theme]);

  const handleUpdateUser = (newUser: UserInfo | null) => {
    setUser(newUser);
    if (newUser) {
      localStorage.setItem('zst_identity_v3', JSON.stringify(newUser));
    } else {
      localStorage.removeItem('zst_identity_v3');
    }
  };

  const handleToggleSave = (id: string) => {
    const newSaved = savedIds.includes(id) ? savedIds.filter(i => i !== id) : [...savedIds, id];
    setSavedIds(newSaved);
    localStorage.setItem('zst_saved_v2', JSON.stringify(newSaved));
  };

  const addToHistory = (id: string) => {
    const filtered = historyIds.filter(i => i !== id);
    const newHistory = [id, ...filtered].slice(0, 15);
    setHistoryIds(newHistory);
    localStorage.setItem('zst_history_v2', JSON.stringify(newHistory));
  };

  const handleRunAppById = (id: string) => {
    const item = allModules.find(m => m.id === id);
    if (item) handleRunApp(item);
  };

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);
    addToHistory(item.id);
    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 800);
  };

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e21': return <ThousandCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return null;
    }
  };

  if (runningAppId) return renderApp();

  const renderContent = () => {
    switch (activeTab) {
      case 'EXPLORE': return <ExploreView />;
      case 'LIBRARY': return <LibraryView allModules={allModules} savedIds={savedIds} historyIds={historyIds} onOpenItem={setSelectedItem} />;
      case 'PROFILE': return (
        <SettingsView 
          theme={theme} 
          onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')} 
          user={user}
          onUpdateUser={handleUpdateUser}
        />
      );
      default:
        return (
          <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
            <main className="max-w-4xl mx-auto px-6 pt-10">
              {/* 搜索框 */}
              <section className="mb-8">
                <div className="relative group">
                  <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
                    <Search className="h-5 w-5 text-slate-400 group-focus-within:text-morandi-charcoal dark:group-focus-within:text-slate-200 transition-colors" />
                  </div>
                  <input
                    type="text"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="搜你所想..."
                    className="w-full pl-12 pr-4 py-4 bg-white/60 dark:bg-dark-card/60 backdrop-blur-md border border-morandi-border dark:border-white/5 rounded-2xl text-sm focus:ring-2 focus:ring-morandi-taupe/20 outline-none transition-all dark:text-slate-100"
                  />
                </div>
              </section>

              {/* AI 灵感 Banner */}
              {!searchQuery && activeCategory === 'ALL' && (
                <KnowledgeBanner onRun={handleRunAppById} />
              )}

              {/* 分类过滤 */}
              <section className="mb-6 mt-4">
                <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
                  {['ALL', 'EDUCATION', 'ENTERTAINMENT', 'UTILITIES'].map((cat) => (
                    <button
                      key={cat}
                      onClick={() => setActiveCategory(cat)}
                      className={`px-6 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${activeCategory === cat ? 'bg-morandi-charcoal text-white dark:bg-slate-200 dark:text-dark-bg border-morandi-charcoal dark:border-slate-200 shadow-sm' : 'bg-white text-slate-400 border-slate-200 dark:bg-dark-card dark:text-slate-500 dark:border-white/5'}`}
                    >
                      {cat === 'ALL' ? '全部' : cat === 'EDUCATION' ? '自然科学' : cat === 'ENTERTAINMENT' ? '逻辑数学' : '通用工具'}
                    </button>
                  ))}
                </div>
              </section>

              {/* 列表显示 */}
              <div className="grid grid-cols-1 gap-1">
                {filteredModules.map((item) => (
                  <AppCard key={item.id} item={item} onClick={setSelectedItem} />
                ))}
                {filteredModules.length === 0 && (
                  <div className="py-20 text-center text-slate-400 italic text-sm">
                    未找到匹配的内容
                  </div>
                )}
              </div>
            </main>
          </div>
        );
    }
  };

  return (
    <div className="h-screen bg-morandi-oatmeal dark:bg-dark-bg text-morandi-charcoal dark:text-slate-300 flex flex-col overflow-hidden transition-colors duration-300">

      <AnimatePresence mode="wait">
        <div className="flex-1 overflow-hidden flex flex-col">
          {renderContent()}
        </div>
      </AnimatePresence>

      {/* iOS 风格底部导航 */}
      <footer className="shrink-0 bg-white/95 dark:bg-dark-card/95 backdrop-blur-xl border-t border-slate-100 dark:border-white/5 pb-8 pt-3 px-6 safe-bottom z-50 transition-colors">
        <div className="flex justify-between items-center max-w-lg mx-auto relative">
          <NavButton icon="grid_view" label="首页" active={activeTab === 'HOME'} onClick={() => setActiveTab('HOME')} />
          <NavButton icon="explore" label="探索" active={activeTab === 'EXPLORE'} onClick={() => setActiveTab('EXPLORE')} />

          <div className="absolute left-1/2 -translate-x-1/2 -top-10">
            <button className="w-14 h-14 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl shadow-xl flex items-center justify-center transform active:scale-90 transition-all">
              <span className="material-icons-outlined text-3xl">add</span>
            </button>
          </div>

          <NavButton icon="favorite_border" label="收藏" active={activeTab === 'LIBRARY'} onClick={() => setActiveTab('LIBRARY')} className="ml-12" />
          <NavButton icon="settings" label="设置" active={activeTab === 'PROFILE'} onClick={() => setActiveTab('PROFILE')} />
        </div>
      </footer>

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          isSaved={savedIds.includes(selectedItem.id)}
          onToggleSave={handleToggleSave}
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

const NavButton = ({ icon, label, active, onClick, className = "" }: { icon: string, label: string, active?: boolean, onClick: () => void, className?: string }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1 w-16 transition-all ${className} ${active ? 'text-morandi-charcoal dark:text-slate-100' : 'text-slate-300 dark:text-slate-600'}`}>
    <span className="material-icons-outlined text-2xl">{icon}</span>
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

import React, { useState, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Sparkles, Send, Loader2, Zap, ArrowUpRight, Atom, Binary, BrainCircuit } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface CatalystResult {
  title: string;
  nucleus: string; // 核心定义
  orbitals: string[]; // 三个关联事实
  logicJump: {
    suggestion: string;
    relatedAppId: string;
  };
}

interface KnowledgeCatalystProps {
  isOpen: boolean;
  onClose: () => void;
  onRunApp: (id: string) => void;
}

const KnowledgeCatalyst: React.FC<KnowledgeCatalystProps> = ({ isOpen, onClose, onRunApp }) => {
  const [input, setInput] = useState('');
  const [isCatalyzing, setIsCatalyzing] = useState(false);
  const [result, setResult] = useState<CatalystResult | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleCatalyze = async () => {
    if (!input.trim() || isCatalyzing) return;
    setIsCatalyzing(true);
    setResult(null);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `分析概念: "${input}"。请将其转化为结构化的知识卡片。`,
        config: {
          responseMimeType: "application/json",
          systemInstruction: "你是一个跨学科知识催化专家。你的任务是把复杂的概念简化为精美的知识节点。relatedAppId 必须从以下集合中选择一个最相关的：e1(地理/天文), e5(文化/诗词), e18(数学/逻辑), ent6(国际象棋/博弈), u1(艺术/绘画), u3(成语/检索)。",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              nucleus: { type: Type.STRING, description: '20字以内的核心本质定义' },
              orbitals: { 
                type: Type.ARRAY, 
                items: { type: Type.STRING },
                description: '三个简短的衍生知识点'
              },
              logicJump: {
                type: Type.OBJECT,
                properties: {
                  suggestion: { type: Type.STRING, description: '联系现实的有趣启发' },
                  relatedAppId: { type: Type.STRING }
                },
                required: ['suggestion', 'relatedAppId']
              }
            },
            required: ['title', 'nucleus', 'orbitals', 'logicJump']
          }
        }
      });

      const data = JSON.parse(response.text) as CatalystResult;
      setResult(data);
    } catch (e) {
      console.error(e);
    } finally {
      setIsCatalyzing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0 }} 
          animate={{ opacity: 1 }} 
          exit={{ opacity: 0 }}
          className="fixed inset-0 z-[100] flex items-center justify-center p-6 sm:p-10"
        >
          {/* 背景模糊层 */}
          <div className="absolute inset-0 bg-morandi-charcoal/20 dark:bg-black/80 backdrop-blur-2xl" onClick={onClose} />

          <motion.div 
            initial={{ scale: 0.9, y: 20, opacity: 0 }}
            animate={{ scale: 1, y: 0, opacity: 1 }}
            exit={{ scale: 0.9, y: 20, opacity: 0 }}
            className="relative w-full max-w-2xl bg-white/10 dark:bg-white/5 border border-white/20 dark:border-white/10 rounded-[3rem] shadow-2xl overflow-hidden flex flex-col"
            onClick={e => e.stopPropagation()}
          >
            {/* 顶栏 */}
            <div className="p-8 flex justify-between items-center shrink-0">
               <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl flex items-center justify-center shadow-lg">
                    <BrainCircuit size={20} className={isCatalyzing ? 'animate-pulse' : ''} />
                  </div>
                  <div>
                    <h3 className="text-lg font-black text-white serif-font italic tracking-tight">知识催化器</h3>
                    <p className="text-[8px] text-white/40 uppercase tracking-[0.3em] font-mono">Input_Concept_Collapse</p>
                  </div>
               </div>
               <button onClick={onClose} className="p-2 text-white/40 hover:text-white transition-colors">
                 <X size={24} />
               </button>
            </div>

            <div className="flex-1 overflow-y-auto no-scrollbar p-8 pt-0">
               {/* 输入区域 */}
               <div className="relative mb-10">
                  <input 
                    ref={inputRef}
                    autoFocus
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleCatalyze()}
                    placeholder="键入任何你想探究的概念..."
                    className="w-full bg-white/5 border-2 border-white/10 rounded-3xl py-6 pl-8 pr-20 text-xl font-bold text-white placeholder:text-white/20 focus:border-white/30 transition-all outline-none"
                  />
                  <button 
                    onClick={handleCatalyze}
                    disabled={isCatalyzing || !input.trim()}
                    className="absolute right-3 top-3 bottom-3 px-6 bg-white dark:bg-slate-200 text-black dark:text-dark-bg rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-2 hover:scale-105 active:scale-95 disabled:opacity-30 transition-all"
                  >
                    {isCatalyzing ? <Loader2 size={16} className="animate-spin" /> : <Send size={16} />}
                  </button>
               </div>

               {/* 结果展示 */}
               <AnimatePresence mode="wait">
                  {isCatalyzing ? (
                    <motion.div 
                      key="loading"
                      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                      className="py-20 flex flex-col items-center justify-center text-center"
                    >
                       <div className="relative mb-8">
                          <div className="w-24 h-24 border-4 border-white/5 border-t-white rounded-full animate-spin"></div>
                          <Atom className="absolute inset-0 m-auto text-white/40 animate-pulse" size={32} />
                       </div>
                       <p className="text-white/60 font-mono text-xs tracking-[0.4em] uppercase animate-pulse">Neural_Processing...</p>
                    </motion.div>
                  ) : result ? (
                    <motion.div 
                      key="result"
                      initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }}
                      className="space-y-8"
                    >
                       <div className="flex flex-col md:flex-row gap-8 items-start">
                          <div className="flex-1">
                             <div className="text-[10px] font-black text-morandi-sage uppercase tracking-[0.3em] mb-3">#Nucleus_定义</div>
                             <h2 className="text-4xl md:text-5xl font-black text-white serif-font mb-4 tracking-tighter leading-none">{result.title}</h2>
                             <p className="text-xl text-white/80 font-bold italic leading-relaxed serif-font">“{result.nucleus}”</p>
                          </div>
                       </div>

                       <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                          {result.orbitals.map((orbit, i) => (
                            <div key={i} className="bg-white/5 border border-white/10 p-5 rounded-2xl group hover:bg-white/10 transition-all">
                               <div className="text-[8px] font-black text-white/20 mb-2 uppercase font-mono tracking-widest">Orbit_0{i+1}</div>
                               <p className="text-xs text-white/70 font-medium leading-relaxed">{orbit}</p>
                            </div>
                          ))}
                       </div>

                       <div className="bg-gradient-to-br from-morandi-blue/20 to-transparent border border-white/10 p-8 rounded-[2.5rem] relative overflow-hidden group">
                          <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:scale-110 transition-transform"><Binary size={60} /></div>
                          <div className="relative z-10">
                             <h4 className="text-[10px] font-black text-white/40 uppercase tracking-widest mb-4 flex items-center gap-2"><Zap size={12} className="text-amber-400" /> 逻辑跃迁 (Logic Jump)</h4>
                             <p className="text-lg text-white font-bold italic mb-6 leading-snug">“{result.logicJump.suggestion}”</p>
                             <button 
                                onClick={() => { onClose(); onRunApp(result.logicJump.relatedAppId); }}
                                className="flex items-center gap-2 text-[10px] font-black text-white/90 bg-white/10 hover:bg-white hover:text-black px-6 py-2.5 rounded-full transition-all uppercase tracking-[0.2em]"
                             >
                                进入关联模块 <ArrowUpRight size={14} />
                             </button>
                          </div>
                       </div>
                    </motion.div>
                  ) : (
                    <div className="py-20 text-center opacity-20">
                       <Zap size={60} className="mx-auto mb-6" />
                       <p className="text-xs font-black text-white uppercase tracking-[0.5em]">Waiting_For_Neural_Impulse</p>
                    </div>
                  )}
               </AnimatePresence>
            </div>

            {/* 页脚 */}
            <div className="p-6 border-t border-white/5 bg-black/20 flex justify-between items-center text-[8px] font-mono text-white/20 tracking-widest uppercase">
               <span>Secure_Connection_771</span>
               <span>Powered by Gemini 3 Flash</span>
            </div>
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default KnowledgeCatalyst;

