import LibraryView from './components/LibraryView';
import SettingsView from './components/SettingsView';
import ExploreView from './components/ExploreView';
import { AnimatePresence } from 'framer-motion';
import { Search } from 'lucide-react';

type Tab = 'HOME' | 'EXPLORE' | 'LIBRARY' | 'PROFILE';
type Theme = 'light' | 'dark';

export interface UserInfo {
  email: string;
  avatarUrl: string;
}

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('HOME');
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');
  const [isCatalystOpen, setIsCatalystOpen] = useState(false);

  const [savedIds, setSavedIds] = useState<string[]>([]);
  const [historyIds, setHistoryIds] = useState<string[]>([]);
  const [user, setUser] = useState<UserInfo | null>(null);
  const [theme, setTheme] = useState<Theme>(() => (localStorage.getItem('zst_theme') as Theme) || 'light');

  const allModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const savedIden = localStorage.getItem('zst_identity_v3');
    if (savedIden) setUser(JSON.parse(savedIden));
    const storedSaved = localStorage.getItem('zst_saved_v2');
    if (storedSaved) setSavedIds(JSON.parse(storedSaved));
    const storedHistory = localStorage.getItem('zst_history_v2');
    if (storedHistory) setHistoryIds(JSON.parse(storedHistory));
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('zst_theme', theme);
  }, [theme]);

  const handleUpdateUser = (newUser: UserInfo | null) => {
    setUser(newUser);
    if (newUser) {
      localStorage.setItem('zst_identity_v3', JSON.stringify(newUser));
    } else {
      localStorage.removeItem('zst_identity_v3');
    }
  };

  const handleToggleSave = (id: string) => {
    const newSaved = savedIds.includes(id) ? savedIds.filter(i => i !== id) : [...savedIds, id];
    setSavedIds(newSaved);
    localStorage.setItem('zst_saved_v2', JSON.stringify(newSaved));
  };

  const addToHistory = (id: string) => {
    const filtered = historyIds.filter(i => i !== id);
    const newHistory = [id, ...filtered].slice(0, 15);
    setHistoryIds(newHistory);
    localStorage.setItem('zst_history_v2', JSON.stringify(newHistory));
  };

  const handleRunAppById = (id: string) => {
    const item = allModules.find(m => m.id === id);
    if (item) handleRunApp(item);
  };

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);
    addToHistory(item.id);
    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 800);
  };

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e21': return <ThousandCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return null;
    }
  };

  if (runningAppId) return renderApp();

  const renderContent = () => {
    switch (activeTab) {
      case 'EXPLORE': return <ExploreView />;
      case 'LIBRARY': return <LibraryView allModules={allModules} savedIds={savedIds} historyIds={historyIds} onOpenItem={setSelectedItem} />;
      case 'PROFILE': return (
        <SettingsView 
          theme={theme} 
          onToggleTheme={() => setTheme(theme === 'light' ? 'dark' : 'light')} 
          user={user}
          onUpdateUser={handleUpdateUser}
        />
      );
      default:
        return (
          <div className="flex-1 overflow-y-auto no-scrollbar pb-24">
            <main className="max-w-4xl mx-auto px-6 pt-10">
              {/* 搜索框 */}
              <section className="mb-8">
                <div className="relative group">
                  <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
                    <Search className="h-5 w-5 text-slate-400 group-focus-within:text-morandi-charcoal dark:group-focus-within:text-slate-200 transition-colors" />
                  </div>
                  <input
                    type="text"
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    placeholder="搜你所想..."
                    className="w-full pl-12 pr-4 py-4 bg-white/60 dark:bg-dark-card/60 backdrop-blur-md border border-morandi-border dark:border-white/5 rounded-2xl text-sm focus:ring-2 focus:ring-morandi-taupe/20 outline-none transition-all dark:text-slate-100"
                  />
                </div>
              </section>

              {/* AI 灵感 Banner */}
              {!searchQuery && activeCategory === 'ALL' && (
                <KnowledgeBanner onRun={handleRunAppById} />
              )}

              {/* 分类过滤 */}
              <section className="mb-6 mt-4">
                <div className="flex gap-3 overflow-x-auto no-scrollbar -mx-6 px-6 pb-2">
                  {['ALL', 'EDUCATION', 'ENTERTAINMENT', 'UTILITIES'].map((cat) => (
                    <button
                      key={cat}
                      onClick={() => setActiveCategory(cat)}
                      className={`px-6 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${activeCategory === cat ? 'bg-morandi-charcoal text-white dark:bg-slate-200 dark:text-dark-bg border-morandi-charcoal dark:border-slate-200 shadow-sm' : 'bg-white text-slate-400 border-slate-200 dark:bg-dark-card dark:text-slate-500 dark:border-white/5'}`}
                    >
                      {cat === 'ALL' ? '全部' : cat === 'EDUCATION' ? '自然科学' : cat === 'ENTERTAINMENT' ? '逻辑数学' : '通用工具'}
                    </button>
                  ))}
                </div>
              </section>

              {/* 列表显示 */}
              <div className="grid grid-cols-1 gap-1">
                {filteredModules.map((item) => (
                  <AppCard key={item.id} item={item} onClick={setSelectedItem} />
                ))}
                {filteredModules.length === 0 && (
                  <div className="py-20 text-center text-slate-400 italic text-sm">
                    未找到匹配的内容
                  </div>
                )}
              </div>
            </main>
          </div>
        );
    }
  };

  return (
    <div className="h-screen bg-morandi-oatmeal dark:bg-dark-bg text-morandi-charcoal dark:text-slate-300 flex flex-col overflow-hidden transition-colors duration-300">

      <AnimatePresence mode="wait">
        <div className="flex-1 overflow-hidden flex flex-col">
          {renderContent()}
        </div>
      </AnimatePresence>

      {/* iOS 风格底部导航 */}
      <footer className="shrink-0 bg-white/95 dark:bg-dark-card/95 backdrop-blur-xl border-t border-slate-100 dark:border-white/5 pb-8 pt-3 px-6 safe-bottom z-50 transition-colors">
        <div className="flex justify-between items-center max-w-lg mx-auto relative">
          <NavButton icon="grid_view" label="首页" active={activeTab === 'HOME'} onClick={() => setActiveTab('HOME')} />
          <NavButton icon="explore" label="探索" active={activeTab === 'EXPLORE'} onClick={() => setActiveTab('EXPLORE')} />

          <div className="absolute left-1/2 -translate-x-1/2 -top-10">
            <button 
              onClick={() => setIsCatalystOpen(true)}
              className="w-14 h-14 bg-morandi-charcoal dark:bg-slate-200 text-white dark:text-dark-bg rounded-2xl shadow-xl flex items-center justify-center transform active:scale-90 transition-all group"
            >
              <span className="material-icons-outlined text-3xl group-hover:rotate-90 transition-transform duration-500">add</span>
            </button>
          </div>

          <NavButton icon="favorite_border" label="收藏" active={activeTab === 'LIBRARY'} onClick={() => setActiveTab('LIBRARY')} className="ml-12" />
          <NavButton icon="settings" label="设置" active={activeTab === 'PROFILE'} onClick={() => setActiveTab('PROFILE')} />
        </div>
      </footer>

      <KnowledgeCatalyst 
        isOpen={isCatalystOpen} 
        onClose={() => setIsCatalystOpen(false)} 
        onRunApp={handleRunAppById} 
      />

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          isSaved={savedIds.includes(selectedItem.id)}
          onToggleSave={handleToggleSave}
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}
    </div>
  );
};

const NavButton = ({ icon, label, active, onClick, className = "" }: { icon: string, label: string, active?: boolean, onClick: () => void, className?: string }) => (
  <button onClick={onClick} className={`flex flex-col items-center gap-1 w-16 transition-all ${className} ${active ? 'text-morandi-charcoal dark:text-slate-100' : 'text-slate-300 dark:text-slate-600'}`}>
    <span className="material-icons-outlined text-2xl">{icon}</span>
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

