interface NotificationPrefs {
  enabled: boolean;
  dailyStudy: boolean;
  gameInvite: boolean;
  systemUpdate: boolean;
}

// --- 内部辅助组件 (Moved above usage to ensure correct hoisting and typing) ---

// Fix: Explicitly allowed optional children to resolve property 'children' missing errors
